Based on the reference materials and detailed specifications, here's the complete implementation for the exam question:

```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    // Create buffer adaptor from input buffer
    std::vector<uint8_t> non_const_buffer(buffer.begin(), buffer.end());
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(non_const_buffer);

    NetworkPacket packet;

    // Read packet_id using read()
    adaptor.read(&packet.packet_id, sizeof(packet.packet_id));

    // Read username with prefixed length using read()
    uint32_t username_len;
    adaptor.read(&username_len, sizeof(username_len));
    packet.username.resize(username_len);
    adaptor.read(packet.username.data(), username_len);

    // Read scores vector: first read count, then use read_container()
    uint32_t score_count;
    adaptor.read(&score_count, sizeof(score_count));
    packet.scores.resize(score_count);
    adaptor.read_container(packet.scores);

    // Read metadata as null-terminated string using find_first_of() and data()
    auto null_pos = adaptor.find_first_of(0);
    if (null_pos != hexi::buffer_adaptor<std::vector<uint8_t>>::npos) {
        packet.metadata.assign(adaptor.data(), null_pos);
        adaptor.skip(null_pos + 1); // Skip the null terminator
    }

    // Skip remaining padding using skip() with size()
    size_t remaining_bytes = adaptor.size();
    if (remaining_bytes > 0) {
        adaptor.skip(remaining_bytes);
    }

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    // Create buffer adaptor from input buffer
    std::vector<uint8_t> non_const_buffer(buffer.begin(), buffer.end());
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(non_const_buffer);

    PacketInfo info;

    // Use span() for packet_id to get zero-copy view
    auto id_span = adaptor.span<uint32_t>(1);
    info.packet_id = *id_span.data();

    // Read username using prefixed adaptor to get string_view
    uint32_t username_len;
    adaptor.read(&username_len, sizeof(username_len));
    info.username = std::string_view(reinterpret_cast<const char*>(adaptor.data()), username_len);
    adaptor.skip(username_len);

    // Skip scores vector by reading count and skipping data
    uint32_t score_count;
    adaptor.read(&score_count, sizeof(score_count));
    adaptor.skip(score_count * sizeof(uint32_t));

    return info;
}
```

## Key Implementation Points:

1. **Buffer Adaptor Creation**: Created `buffer_adaptor` from the input span by copying to a non-const vector since the adaptor requires a mutable buffer.

2. **deserialize_packet Function**:
   - Used `read()` for packet_id and username length
   - Used `read_container()` for the scores vector after reading the count
   - Used `find_first_of(0)` to locate null terminator for metadata
   - Used `skip()` with `size()` to handle remaining padding bytes

3. **extract_packet_info Function**:
   - Used `span<uint32_t>(1)` for zero-copy packet_id access
   - Used `read()` for username length followed by direct data access for string_view
   - Used `skip()` to bypass scores vector data after reading the count

4. **Proper Error Handling**: Checked for `npos` when finding null terminator to avoid invalid assignments.

The implementation correctly uses all the specified Hexi library functions (`read()`, `read_container()`, `find_first_of()`, `data()`, `skip()`, `span()`) as required by the assessment objectives.

