#include <cstdint>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create a block_allocator for uint8_t with the specified element count
    hexi::block_allocator<uint8_t, element_count> allocator;

    // Demonstrate allocation and deallocation to show free list management

    // First allocation - uses preallocated blocks if available
    uint8_t* block1 = allocator.allocate();
    // Internally: 
    // - If free_list_ is not empty, pop() removes the head block
    // - Otherwise, falls back to new T()

    // Second allocation - continues using preallocated blocks
    uint8_t* block2 = allocator.allocate();
    // Internally: 
    // - If free_list_ has previous blocks, pop() removes the new head
    // - Otherwise, falls back to new T()

    // Deallocate first block - returns it to the free list
    allocator.deallocate(block1);
    // Internally: push() adds the block to the head of free_list_

    // Deallocate second block - returns it to the free list
    allocator.deallocate(block2);
    // Internally: push() adds the block to the head of free_list_

    // Subsequent allocations will use the returned blocks first
    uint8_t* block3 = allocator.allocate();
    // Internally: pop() retrieves the first deallocated block (block2)

    // Continue demonstrating the LIFO behavior of the free list
}

