```cpp
#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>

std::vector<uint8_t> read_file_data(const std::filesystem::path& file_path, size_t bytes_to_read) {
    hexi::file_buffer buffer(file_path);
    if (!buffer) {
        return {}; // Return empty vector if file cannot be opened
    }

    std::vector<uint8_t> result(bytes_to_read);
    buffer.read(result.data(), bytes_to_read);
    return result;
}

std::vector<uint8_t> preview_file_data(const std::filesystem::path& file_path, size_t bytes_to_preview) {
    hexi::file_buffer buffer(file_path);
    if (!buffer) {
        return {}; // Return empty vector if file cannot be opened
    }

    // Ensure we don't try to preview more data than available
    size_t actual_bytes = bytes_to_preview;
    if (bytes_to_preview > buffer.size()) {
        actual_bytes = buffer.size();
    }

    std::vector<uint8_t> result(actual_bytes);
    buffer.copy(result.data(), actual_bytes);
    return result;
}

void write_file_data(const std::filesystem::path& file_path, const std::vector<uint8_t>& data) {
    hexi::file_buffer buffer(file_path);
    if (!buffer) {
        return; // Do nothing if file cannot be opened
    }

    if (!data.empty()) {
        buffer.write(data.data(), data.size());
    }
}

size_t get_file_size(const std::filesystem::path& file_path) {
    hexi::file_buffer buffer(file_path);
    if (!buffer) {
        return 0; // Return 0 if file cannot be opened
    }

    return buffer.size();
}
```

