std::vector<uint8_t> write_and_read_data(const std::vector<uint8_t>& input_data) {
    // Create a buffer to hold the data
    std::vector<uint8_t> buffer;

    // Create buffer_write_adaptor instance
    hexi::pmc::buffer_write_adaptor<std::vector<uint8_t>> write_adaptor(buffer);

    // Check available space using free() before writing
    if (write_adaptor.free() < input_data.size()) {
        // Resize buffer if needed to accommodate the data
        buffer.resize(input_data.size());
    }

    // Write data using write() method
    write_adaptor.write(input_data.data(), input_data.size());

    // Create buffer_read_adaptor instance
    hexi::pmc::buffer_read_adaptor<std::vector<uint8_t>> read_adaptor(buffer);

    // Check available data size using size()
    std::size_t data_size = read_adaptor.size();

    // Read data back using read() method
    std::vector<uint8_t> output_data(data_size);
    read_adaptor.read(output_data.data(), data_size);

    return output_data;
}

std::vector<uint8_t> peek_data_without_advancing(const std::vector<uint8_t>& buffer_data, std::size_t peek_size) {
    // Create buffer_read_adaptor instance
    hexi::pmc::buffer_read_adaptor<const std::vector<uint8_t>> read_adaptor(buffer_data);

    // Check available data size using size()
    std::size_t available_size = read_adaptor.size();

    // Validate peek size doesn't exceed available data
    if (peek_size > available_size) {
        peek_size = available_size; // Peek only available data
    }

    // Use copy() to peek at data without advancing read pointer
    std::vector<uint8_t> peek_buffer(peek_size);
    read_adaptor.copy(peek_buffer.data(), peek_size);

    // Use read_ptr() to get pointer to current read position (for verification)
    const uint8_t* read_pointer = read_adaptor.read_ptr();

    // Use read() to actually consume the data after peeking
    read_adaptor.read(nullptr, 0); // This would normally consume, but we want to keep the data

    // For demonstration, we'll return the peeked data
    return peek_buffer;
}
