    stream.write(converted_message_id);

    // Convert each element in data_values from native to big-endian and write container
    std::vector<uint16_t> converted_data_values;
    converted_data_values.reserve(packet.data_values.size());
    for (const auto& value : packet.data_values) {
        converted_data_values.push_back(hexi::endian::native_to_big(value));
    }
    stream.write_container(converted_data_values);

    // Convert checksum from native to big-endian and write
    uint32_t converted_checksum = hexi::endian::native_to_big(packet.checksum);
    stream.write(converted_checksum);

