        double converted_pressure = hexi::endian::conditional_reverse(
            std::endian::native, std::endian::little, pressure
        );
        adaptor.write(converted_pressure);
    }

    void serialise(auto& adaptor) {
        // Deserialization: read and convert from little-endian to native
        adaptor.read(sensor_id);

        temperatures.clear();
        for (size_t i = 0; i < temperatures.size(); ++i) {
            float temp_value;
            adaptor.read(temp_value);
            hexi::endian::little_to_native_inplace(temp_value);
            temperatures.push_back(temp_value);
        }

        adaptor.read(pressure);
        hexi::endian::little_to_native_inplace(pressure);
